import{_ as d,o as a,c as e,a5 as o}from"./chunks/framework.D9Kapg2s.js";const u=JSON.parse('{"title":"使用模式","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/modes.md","filePath":"zh/guide/modes.md"}'),i={name:"zh/guide/modes.md"};function s(l,t,r,c,n,h){return a(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="使用模式" tabindex="-1">使用模式 <a class="header-anchor" href="#使用模式" aria-label="Permalink to &quot;使用模式&quot;">​</a></h1><p>LinguaFlow 提供两种运行模式，分别适用于不同的使用场景。</p><h2 id="本地模式" tabindex="-1">本地模式 <a class="header-anchor" href="#本地模式" aria-label="Permalink to &quot;本地模式&quot;">​</a></h2><p>本地模式适用于个人使用，无需登录认证，数据存储在本地。后端会自动创建一个名为 <code>local</code> 的本地用户，所有请求自动以该用户身份通过认证，完全跳过 JWT 验证流程。</p><h3 id="启动方式" tabindex="-1">启动方式 <a class="header-anchor" href="#启动方式" aria-label="Permalink to &quot;启动方式&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">linguaflow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local</span></span></code></pre></div><p>或者直接双击运行 <code>linguaflow</code>（Windows）/ <code>./linguaflow</code>（Linux/macOS），程序通过 <code>mousetrap</code> 检测到双击启动后，自动以本地模式运行。</p><p>启动后会自动打开浏览器访问 <code>http://127.0.0.1:18080</code>。</p><h3 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h3><ul><li><strong>无需登录</strong> — 启动即可使用，前端自动跳过登录和注册页面</li><li><strong>自动打开浏览器</strong> — 默认访问 <code>http://127.0.0.1:18080</code>，可通过 <code>--no-browser</code> 禁用</li><li><strong>嵌入式前端</strong> — 前端静态资源打包在后端二进制中，无需单独部署</li><li><strong>本地数据存储</strong> — SQLite 数据库，数据目录为系统用户配置目录下的 <code>LinguaFlow</code> 文件夹</li><li><strong>端口冲突处理</strong> — 如果端口被占用，自动递增端口号，最多尝试 10 次</li><li><strong>CORS 限制</strong> — 仅允许来自 <code>127.0.0.1</code> 和 <code>localhost</code> 的请求</li></ul><h3 id="配置选项" tabindex="-1">配置选项 <a class="header-anchor" href="#配置选项" aria-label="Permalink to &quot;配置选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>描述</th><th>默认值</th></tr></thead><tbody><tr><td><code>--port</code></td><td>监听端口</td><td><code>18080</code></td></tr><tr><td><code>--host</code></td><td>监听地址</td><td><code>127.0.0.1</code></td></tr><tr><td><code>--db</code></td><td>数据库路径</td><td><code>UserConfigDir/LinguaFlow/data.db</code></td></tr><tr><td><code>--no-browser</code></td><td>不自动打开浏览器</td><td><code>false</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">数据目录说明</p><p><code>UserConfigDir</code> 因操作系统而异：</p><ul><li>Windows: <code>%AppData%</code>（如 <code>C:\\Users\\&lt;用户名&gt;\\AppData\\Roaming</code>）</li><li>macOS: <code>~/Library/Application Support</code></li><li>Linux: <code>~/.config</code>（遵循 <code>XDG_CONFIG_HOME</code>）</li></ul></div><h2 id="服务器模式" tabindex="-1">服务器模式 <a class="header-anchor" href="#服务器模式" aria-label="Permalink to &quot;服务器模式&quot;">​</a></h2><p>服务器模式适用于团队协作，支持多用户、认证和权限管理。</p><h3 id="启动方式-1" tabindex="-1">启动方式 <a class="header-anchor" href="#启动方式-1" aria-label="Permalink to &quot;启动方式&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">linguaflow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div><h3 id="特点-1" tabindex="-1">特点 <a class="header-anchor" href="#特点-1" aria-label="Permalink to &quot;特点&quot;">​</a></h3><ul><li><strong>多租户</strong> — 支持多用户注册和登录</li><li><strong>JWT 认证</strong> — 基于 Token 的身份验证（Access Token 有效期 15 分钟，Refresh Token 有效期 30 天）</li><li><strong>RBAC 权限</strong> — 基于角色的访问控制</li><li><strong>组织管理</strong> — 支持组织和团队管理</li><li><strong>网络访问</strong> — 默认监听 <code>0.0.0.0</code>，支持局域网/公网访问</li><li><strong>用户注册</strong> — 默认开放注册，首个注册用户自动成为管理员</li><li><strong>前端独立部署</strong> — 不提供前端静态资源，需单独部署前端应用</li></ul><h3 id="配置选项-1" tabindex="-1">配置选项 <a class="header-anchor" href="#配置选项-1" aria-label="Permalink to &quot;配置选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>描述</th><th>默认值</th></tr></thead><tbody><tr><td><code>--port</code></td><td>监听端口</td><td><code>8080</code></td></tr><tr><td><code>--host</code></td><td>监听地址</td><td><code>0.0.0.0</code></td></tr><tr><td><code>--db</code></td><td>数据库路径</td><td><code>./data/data.db</code></td></tr><tr><td><code>--auto-migrate</code></td><td>自动迁移数据库</td><td><code>true</code></td></tr></tbody></table><h3 id="管理员配置" tabindex="-1">管理员配置 <a class="header-anchor" href="#管理员配置" aria-label="Permalink to &quot;管理员配置&quot;">​</a></h3><p>服务器模式下，可通过环境变量配置初始管理员账户：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LINGUAFLOW_ADMIN_USERNAME</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">admin</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> LINGUAFLOW_ADMIN_PASSWORD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">your-secure-password</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">linguaflow</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span></span></code></pre></div><p>如果未设置环境变量，首个注册的用户将自动成为管理员（取决于配置中 <code>registration.auto_admin</code> 的设置）。</p><div class="warning custom-block"><p class="custom-block-title">安全提示</p><p>服务器模式下，请确保：</p><ul><li>使用强密码</li><li>修改默认的 JWT Secret（配置项 <code>server.jwt_secret</code>）</li><li>在生产环境中配置 HTTPS（通过反向代理）</li><li>限制监听地址为内网或配置防火墙</li></ul></div><h2 id="模式对比" tabindex="-1">模式对比 <a class="header-anchor" href="#模式对比" aria-label="Permalink to &quot;模式对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>本地模式</th><th>服务器模式</th></tr></thead><tbody><tr><td>CLI 命令</td><td><code>linguaflow local</code></td><td><code>linguaflow serve</code></td></tr><tr><td>用户认证</td><td>自动认证（跳过 JWT）</td><td>JWT Token 认证</td></tr><tr><td>多用户</td><td>单用户（<code>local</code> 用户）</td><td>多租户</td></tr><tr><td>用户注册</td><td>不支持</td><td>默认开放</td></tr><tr><td>默认端口</td><td><code>18080</code></td><td><code>8080</code></td></tr><tr><td>默认监听</td><td><code>127.0.0.1</code></td><td><code>0.0.0.0</code></td></tr><tr><td>数据目录</td><td><code>UserConfigDir/LinguaFlow</code></td><td><code>./data</code></td></tr><tr><td>前端资源</td><td>嵌入在二进制中</td><td>需单独部署</td></tr><tr><td>CORS 策略</td><td>仅 localhost</td><td>可配置（默认 <code>*</code>）</td></tr><tr><td>自动打开浏览器</td><td>是</td><td>否</td></tr><tr><td>双击启动</td><td>自动进入本地模式</td><td>不支持</td></tr><tr><td>适用场景</td><td>个人使用</td><td>团队协作</td></tr></tbody></table><h2 id="前端模式适配" tabindex="-1">前端模式适配 <a class="header-anchor" href="#前端模式适配" aria-label="Permalink to &quot;前端模式适配&quot;">​</a></h2><p>前端应用会通过 <code>/api/v1/mode</code> 接口（无需认证）自动检测当前运行模式，并据此调整行为：</p><ul><li><strong>本地模式</strong>：跳过登录/注册页面，直接进入主界面；用户菜单仅显示&quot;连接远程服务&quot;选项；顶部显示绿色 &quot;本地模式&quot; 标签</li><li><strong>服务器模式</strong>：需要登录后才能访问；用户菜单显示&quot;切换服务&quot;和&quot;退出登录&quot;选项</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>阅读 <a href="/zh/guide/configuration.html">配置</a> 了解详细配置选项</li><li>阅读 <a href="/zh/guide/cli.html">CLI 命令行</a> 了解所有可用命令</li></ul>`,33)])])}const g=d(i,[["render",s]]);export{u as __pageData,g as default};
